import { ORDINAL_DATATYPE } from '../../../core/datatype-constants';
import { getLegendBound } from '../../../legend/legend-bound';
import { isHeatMapChartType } from '../../../events/events-utils';
import { ScaleRegistry } from '../../../scale/scale-registry';
import { sizeCorrection } from './size-correction';

export function sizeRangeParser(encodeType, index, config, chart, customMax) {
    let dataSet = chart.dataset,
        dataType = dataSet.getDataType(encodeType),
        { ranges, sizes: userSizes } = config,
        bound = getLegendBound(config, chart.chartarea, customMax),
        rangeOperators = {};

    if (userSizes) {
        rangeOperators.userRanges = {
            size: userSizes,
            plotBound: _isMatrix(chart) ? null : chart.plotarea,
            callbackArgs: [chart, bound]
        };
        return rangeOperators;
    }

    rangeOperators.baseSize = {
        config,
        size: _defaultPercent(chart),
        plotBound: _isMatrix(chart) ? null : chart.plotarea,
        correction: _ => sizeCorrection(_, bound, { config, dataType }, chart),
        callbackArgs: [chart, bound]
    };

    if (ranges || dataType === ORDINAL_DATATYPE) {
        rangeOperators.mapDiscreteDomainToRange = { ranges };
    } else {
        rangeOperators.mapContinuousDomainToRange = {};
    }

    return rangeOperators;
}

function _defaultPercent(chart) {
    return _isMatrix(chart) ? ['25%', '100%'] : chart.systemConf.legend.singleLayout ? ['2.5%', '25%'] : ['2%', '20%'];
}

function _isMatrix(chart) {
    let chartType = chart.chartTypes[0].value;
    return isHeatMapChartType(chartType);
}

ScaleRegistry.add('size.rangeParser', sizeRangeParser);
